package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.AbstractBijdragePercentages;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.AsbestfondsManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.APKConstant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import be.schaubroeck.lpb.tools.rsz.KengetalMapper;
import be.schaubroeck.lpb.tools.rsz.KengetalMapperFactory;
import be.schaubroeck.lpb.tools.rsz.dmfappl.CategorieKengetalStatuutPensioenstelselDmfappl;
import be.schaubroeck.lpb.tools.service.APKConstantService;
import be.schaubroeck.lpb.tools.service.DmfaVerminderingsPercentageService;
import be.schaubroeck.lpb.tools.service.DmfapplBasisBijdrageService;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

public class DmfapplBijdragePercentages extends AbstractBijdragePercentages {

    private final APKConstantService apkConstantService;

    public DmfapplBijdragePercentages(
            ConstantManager constantManager, RegulManager regulManager, RszConstantService rszConstantService,
            APKConstantService apkConstantService, DmfapplBasisBijdrageService dmfapplBasisBijdrageService,
            DmfaVerminderingsPercentageService dmfaVerminderingsPercentageService, RekenTijd rekenTijd) {
        super(constantManager, regulManager, rszConstantService, dmfapplBasisBijdrageService, dmfaVerminderingsPercentageService, new IsPool2TerDmfappl(constantManager),
                new AsbestfondsManager(constantManager), rekenTijd);
        this.apkConstantService = apkConstantService;
    }

    @Override
    public BigDecimal getInhoudingDubbelVakantiegeld(SleutelGegevens gegevens, LocalDate zoekDatum) {
        KengetalMapper werknemersKengetalMapper = getWerknemersKengetalMapper(zoekDatum);
        return getInhoudingsPercentage(gegevens, zoekDatum, werknemersKengetalMapper.getBijdrageDubbelVakantieGeld(), gegevens.getWerkgeversCategorie());
    }

    @Override
    public BigDecimal getInhoudingsPercentageDubbelVakantiegeldMandataris(SleutelGegevens gegevens, LocalDate zoekDatum) {
        KengetalMapper kengetalMapper = KengetalMapperFactory.getKengetalMapper(zoekDatum);
        DmfapplWnkengetal werknemersKengetalBijdrage = kengetalMapper.getBijdrageDubbelVakantieGeldMandataris();
        WerkgeversCategorie werkgeversCategorie = getWerkgeversCategorie(gegevens);

        return getInhoudingsPercentage(gegevens, zoekDatum, werknemersKengetalBijdrage, werkgeversCategorie);
    }

    public WerkgeversCategorie getWerkgeversCategorie(SleutelGegevens gegevens) {
        WerkgeversCategorie werkgeversCategorie = gegevens.getWerkgeversCategorie();
        if (werkgeversCategorie == WerkgeversCategorie.NVT) {
            werkgeversCategorie = WerkgeversCategorie.BIJZONDERE_CATEGORIEEN;
        }
        return werkgeversCategorie;
    }

    @Override
    public BigDecimal getInhoudingPensioenVastbenoemdenApk(SleutelGegevens gegevens, LocalDate zoekDatum) {
        APKConstant apkConstant = apkConstantService.getByKey(
                gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(), gegevens.getPensioenStelsel(), zoekDatum);

        BigDecimal inhoudingPercentage = (apkConstant != null) ? apkConstant.getWerknemersPercentage() : BigDecimal.ZERO;
        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    @Override
    public BigDecimal getPatronaleBijdragePensioenVastbenoemdenApk(SleutelGegevens gegevens, LocalDate zoekDatum) {
        APKConstant apkConstant = apkConstantService.getByKey(
                gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(), gegevens.getPensioenStelsel(), zoekDatum);

        BigDecimal inhoudingPercentage = (apkConstant != null) ? apkConstant.getWerkgeversPercentage() : BigDecimal.ZERO;
        return inhoudingPercentage.movePointLeft(SCHUIF_FACTOR_100);
    }

    @Override
    protected CategorieKengetalStatuutPensioenstelsel getCategorieKengetalStatuutPensioenstelsel(SleutelGegevens gegevens) {
        return new CategorieKengetalStatuutPensioenstelselDmfappl(gegevens.getWerkgeversCategorie(), gegevens.getWerknemersKengetal(), DmfapplStatuutDmfappl.NVT,
                gegevens.getPensioenStelsel());
    }

}
